class Solution:
    def longestConsecutive(self, nums: list[int]) -> int:
        S = set(nums)
        best = 0
        for x in S:
            if x - 1 in S:
                continue            # 不是序列起点,跳过
            y = x
            while y + 1 in S:
                y += 1
            best = max(best, y - x + 1)
        return best
